class Solution(object):
    def countSymmetricIntegers(self, low, high):
        count = 0
        for x in range(low, high + 1):
            s = str(x)
            if len(s) % 2 == 1:
                continue
            half = len(s) // 2
            if sum(int(c) for c in s[:half]) == sum(int(c) for c in s[half:]):
                count += 1
        return count
